## 5) `mla_fwd_kernel.h`：Phase1 核心 compute（重点）
我们复制 `compute_attn_1rowblock` 的结构，但删掉 dropout、Return_softmax、mask类、以及 BlockInfo varlen。只保留：

- shared 分配
- gmem tensor 构造（类似你贴的 120–260 行，但用 params 自己算 offset）
- dv loop 累加 QK
- softmax_rescale_o 作用到多个 acc_o
- per-tile copy V + gemm_rs 更新对应 acc_o
- 最后用 inv_l 归一化每个 acc_o 并写回 O 到 dv 对应位置

### 关键实现骨架（写法示意）
```cpp
#pragma once
#include "namespace_config.h"
#include <cute/tensor.hpp>
#include "kernel_traits.h"
#include "utils.h"
#include "softmax.h"
#include "mla.h"
#include "mla_mask.h"

namespace FLASH_NAMESPACE {
using namespace cute;

template<typename Kernel_traits, int NTILES, bool Is_even_K, typename Params>
__device__ inline void compute_mla_attn_1rowblock(const Params &params, int bidb, int bidh, int m_block) {
    using Element = typename Kernel_traits::Element;          // bf16
    using ElementAccum = typename Kernel_traits::ElementAccum; // float
    using index_t = typename Kernel_traits::index_t;

    extern __shared__ char smem_[];
    int tidx = threadIdx.x;

    constexpr int kBlockM = Kernel_traits::kBlockM;
    constexpr int kBlockN = Kernel_traits::kBlockN;
    constexpr int kHeadDim = Kernel_traits::kHeadDim; // 128
    constexpr int kNWarps = Kernel_traits::kNWarps;

    int seqlen_q = params.seqlen_q;
    int kv_len = params.kv_valid_len[bidb];
    if (m_block * kBlockM >= seqlen_q) return;

    // end_n blocks (use kv_len)
    int n_block_min = 0;
    int n_block_max = (kv_len + kBlockN - 1) / kBlockN;
    int past = kv_len - seqlen_q;
    if (params.causal) {
        int max_qpos = past + min((m_block + 1) * kBlockM, seqlen_q) - 1;
        int causal_max = (max_qpos + 1 + kBlockN - 1) / kBlockN;
        if (causal_max < n_block_max) n_block_max = causal_max;
    }
    if (n_block_max <= n_block_min) {
        // 写 0 到输出 slice 并 return（dv_start..dv_start+dv_len）
        return;
    }

    // ---- 构造 mQ/mK/mV: 注意 shape 的最后维度用 params.dc，但 local_tile 用 128 ----
    auto q_base = reinterpret_cast<Element*>(params.q_ptr)
        + bidb * params.q_batch_stride + bidh * params.q_head_stride + (m_block * kBlockM) * params.q_row_stride;
    auto k_base = reinterpret_cast<Element*>(params.k_ptr)
        + bidb * params.k_batch_stride; // head=1，所以不加 head_stride

    // mQ: (seqlen_q, 1, dc) 这里把 head维预先索引掉了
    Tensor mQ = make_tensor(make_gmem_ptr(q_base),
        make_shape(seqlen_q - m_block * kBlockM, params.dc),
        make_stride(params.q_row_stride, _1{}));

    // mK/mV: (kv_len, dc)
    Tensor mK = make_tensor(make_gmem_ptr(k_base),
        make_shape(kv_len, params.dc),
        make_stride(params.k_row_stride, _1{}));
    Tensor mV = mK; // V == K_nope

    // shared
    Tensor sQ = make_tensor(make_smem_ptr(reinterpret_cast<Element*>(smem_)), typename Kernel_traits::SmemLayoutQ{});
    Tensor sK = make_tensor(sQ.data() + (Kernel_traits::Share_Q_K_smem ? 0 : size(sQ)), typename Kernel_traits::SmemLayoutKV{});
    Tensor sV = make_tensor(sK.data() + size(sK), typename Kernel_traits::SmemLayoutKV{});
    Tensor sVt = make_tensor(sV.data(), typename Kernel_traits::SmemLayoutVtransposed{});
    Tensor sVtNoSwizzle = make_tensor(sV.data().get(), typename Kernel_traits::SmemLayoutVtransposedNoSwizzle{});

    typename Kernel_traits::GmemTiledCopyQKV gmem_tiled_copy_QKV;
    auto gmem_thr_copy_QKV = gmem_tiled_copy_QKV.get_thread_slice(tidx);

    typename Kernel_traits::TiledMma tiled_mma;
    auto thr_mma = tiled_mma.get_thread_slice(tidx);

    Tensor tSrQ  = thr_mma.partition_fragment_A(sQ);
    Tensor tSrK  = thr_mma.partition_fragment_B(sK);
    Tensor tOrVt = thr_mma.partition_fragment_B(sVtNoSwizzle);

    // multi-tile acc_o
    Tensor acc_o[NTILES];
    #pragma unroll
    for (int i=0;i<NTILES;++i) {
        acc_o[i] = partition_fragment_C(tiled_mma, Shape<Int<kBlockM>, Int<kHeadDim>>{});
        clear(acc_o[i]);
    }

    Softmax<2 * size<1>(acc_o[0])> softmax; // same template as original

    // ---- main loop over n_block (可以先正序，后续再恢复原来的 reverse优化) ----
    for (int n_block = n_block_min; n_block < n_block_max; ++n_block) {
        Tensor acc_s = partition_fragment_C(tiled_mma, Shape<Int<kBlockM>, Int<kBlockN>>{});
        clear(acc_s);

        // QK accumulate over dv in [0, dc) step 128
        for (int dv = 0; dv < params.dc; dv += 128) {
            // gQ_dv: (kBlockM, 128)
            Tensor gQ = local_tile(mQ(_, _), Shape<Int<kBlockM>, Int<kHeadDim>>{}, make_coord(0, dv));
            // gK_dv: (kBlockN, 128)
            Tensor gK = local_tile(mK(_, _), Shape<Int<kBlockN>, Int<kHeadDim>>{}, make_coord(n_block * kBlockN, dv));

            Tensor tQgQ = gmem_thr_copy_QKV.partition_S(gQ);
            Tensor tQsQ = gmem_thr_copy_QKV.partition_D(sQ);
            Tensor tKgK = gmem_thr_copy_QKV.partition_S(gK);
            Tensor tKsK = gmem_thr_copy_QKV.partition_D(sK);

            // predicates：可先忽略 Is_even_K 情况（dc 一般是 896/512，都是 128倍数）
            // copy Q,K to shared
            FLASH_NAMESPACE::copy</*Is_even_MN=*/false, /*Is_even_K=*/true>(gmem_tiled_copy_QKV, tQgQ, tQsQ);
            FLASH_NAMESPACE::copy</*Is_even_MN=*/false, /*Is_even_K=*/true>(gmem_tiled_copy_QKV, tKgK, tKsK);
            cute::cp_async_fence();
            FLASH_NAMESPACE::cp_async_wait<0>();
            __syncthreads();

            // gemm accumulate to acc_s
            FLASH_NAMESPACE::gemm</*A_in_regs=*/Kernel_traits::Is_Q_in_regs>(
                acc_s, tSrQ, tSrK, /*tSsQ*/{}, /*tSsK*/{}, tiled_mma, /*smem copies*/{}, {}, {}, {}
            );
            __syncthreads();
        }

        // mask acc_s with kv_len + causal
        apply_mask_mla(acc_s, n_block * kBlockN, m_block, kBlockM, kBlockN,
                       seqlen_q, kv_len, past, tidx, kNWarps);

        // rescale each acc_o tile with same acc_s
        #pragma unroll
        for (int i=0;i<NTILES;++i) {
            if (n_block == n_block_min) {
                softmax.template softmax_rescale_o</*Is_first=*/true, /*Check_inf=*/true>(acc_s, acc_o[i], params.scale_softmax_log2);
            } else {
                softmax.template softmax_rescale_o</*Is_first=*/false, /*Check_inf=*/true>(acc_s, acc_o[i], params.scale_softmax_log2);
            }
        }

        // build P fragment from acc_s
        Tensor rP = FLASH_NAMESPACE::convert_type<Element>(acc_s);
        Tensor tOrP = make_tensor(rP.data(), FLASH_NAMESPACE::convert_layout_acc_Aregs<typename Kernel_traits::TiledMma>(rP.layout()));

        // PV for each output tile
        #pragma unroll
        for (int i=0;i<NTILES;++i) {
            int dv_out = params.dv_start + i * 128;
            Tensor gV = local_tile(mV(_, _), Shape<Int<kBlockN>, Int<kHeadDim>>{}, make_coord(n_block * kBlockN, dv_out));
            Tensor tVgV = gmem_thr_copy_QKV.partition_S(gV);
            Tensor tVsV = gmem_thr_copy_QKV.partition_D(sV);

            FLASH_NAMESPACE::copy</*Is_even_MN=*/false, /*Is_even_K=*/true>(gmem_tiled_copy_QKV, tVgV, tVsV);
            cute::cp_async_fence();
            FLASH_NAMESPACE::cp_async_wait<0>();
            __syncthreads();

            FLASH_NAMESPACE::gemm_rs(acc_o[i], tOrP, tOrVt, /*tOsVt*/{}, tiled_mma, /*smem copy V*/{}, /*thr copy V*/{});
            __syncthreads();
        }
    }

    // finalize: get inv_l from softmax (你需要在 softmax.h 新增接口)
    auto inv_l = softmax.get_inv_l();  // per-row
    #pragma unroll
    for (int i=0;i<NTILES;++i) {
        softmax.apply_inv_l(acc_o[i], inv_l);
        Tensor rO = FLASH_NAMESPACE::convert_type<Element>(acc_o[i]);
        // store rO -> O at dv_start + i*128
    }
}
} // namespace
```

上面是骨架，用于表达“哪些地方插入 dv loop / tile loop / mask”。实际实现你们会复用原 compute_attn_1rowblock 中的 `tSsQ/tSsK/smem_tiled_copy_Q/K/V` 等对象，而不是空 `{}`。但关键结构就是这样。

