void run_mha_fwd_hdim256(Flash_fwd_params &params, cudaStream_t stream) {
    constexpr static int Headdim = 256;
    int device;
    cudaGetDevice(&device);
    int max_smem_per_sm, max_smem_per_block;
    cudaError status_ = cudaDeviceGetAttribute(
        &max_smem_per_sm, cudaDevAttrMaxSharedMemoryPerMultiprocessor, device);
    status_ = cudaDeviceGetAttribute(
        &max_smem_per_block, cudaDevAttrMaxSharedMemoryPerBlockOptin, device);
    if (status_ != cudaSuccess) {
      C10_CUDA_CHECK(status_);
    }
    // printf("max_smem_per_sm = %d, max_smem_per_block = %d\n", max_smem_per_sm, max_smem_per_block);
    DROPOUT_SWITCH(params.p_dropout < 1.f, Is_dropout, [&] {
        // For A100, we want to run with 128 x 64 (128KB smem).
        // For H100 we want to run with 64 x 64 (96KB smem) since then we can get 2 CTAs per SM.
        if (max_smem_per_block >= 2 _Headdim_ (128 + 2 _64) && max_smem_per_sm < 4_ Headdim _(64 + 2_ 64)) {
            run_flash_fwd<Flash_fwd_kernel_traits<Headdim, 128, 64, 8, false, false, T>, Is_dropout, Is_causal>(params, stream);
        } else {
            run_flash_fwd<Flash_fwd_kernel_traits<Headdim, 64, 64, 4, false, false, T>, Is_dropout, Is_causal>(params, stream);
        }
        // 64 KB
        // run_flash_fwd<Flash_fwd_kernel_traits<Headdim, 64, 32, 4, false, false, T>, Is_dropout, Is_causal>(params, stream);
        // 96 KB
        // run_flash_fwd<Flash_fwd_kernel_traits<Headdim, 128, 32, 8, false, false, T>, Is_dropout, Is_causal>(params, stream);
    });
}
}  // namespace FLASH_NAMESPACE

这段 `run_mha_fwd_hdim128` 给了我们 Phase1 最关键的信息：**flash-attn 在 head_dim=128、无 dropout、causal 场景下默认用的 traits 是：**

- 对 H100/H200（不是 sm86/sm89 的 sm8x 分支）：  
  `Flash_fwd_kernel_traits<128, 128, 64, 4, false, false, T>`  
  也就是：
  - `kBlockM=128`
  - `kBlockN=64`
  - `kNWarps=4`（128 threads）
  - head_dim=128
  - Q不在regs、Q/K不共享smem

对你们 Phase1（NTILES=4/3，多 acc_o），这套配置**反而是很合适的起点**：因为 warps 少、寄存器压力相对小。

下面我给出**Phase1 的具体整合实现方案**：你们可以直接照这个在 `flash_fwd_launch_template.h` 基础上加出 `run_mla_fwd_hdim128`，并写一个最小 `mla_fwd_kernel.h` 来跑通。

