### 1.2 写一个 launcher：run_mla_fwd_tiles
```cpp
template<typename Kernel_traits, int NTILES>
static inline void run_mla_fwd_tiles(Mla_fwd_params &params, cudaStream_t stream) {
    constexpr size_t smem_size = Kernel_traits::kSmemSize;
    const int num_m_block = (params.seqlen_q + Kernel_traits::kBlockM - 1) / Kernel_traits::kBlockM;
    dim3 grid(num_m_block, params.b, params.h);

    // Phase1：128 tile，dv_start/dv_len 也按 128 对齐，所以 Is_even_K 恒 true
    constexpr bool IsEvenKConst = true;
    // 为了先跑通，Is_even_MN 先用 false（不用走复杂的“无mask快路径”）
    constexpr bool IsEvenMNConst = false;

    auto kernel = &mla_fwd_kernel<Kernel_traits, NTILES, IsEvenMNConst, IsEvenKConst>;
    if (smem_size >= 48 * 1024) {
        C10_CUDA_CHECK(cudaFuncSetAttribute(kernel, cudaFuncAttributeMaxDynamicSharedMemorySize, smem_size));
    }
    kernel<<<grid, Kernel_traits::kNThreads, smem_size, stream>>>(params);
    C10_CUDA_KERNEL_LAUNCH_CHECK();
}
```

### 1.3 新增 `run_mla_fwd_hdim128<bf16,true>`
直接照抄 `run_mha_fwd_hdim128` 的选择逻辑，但换成 `run_mla_fwd_tiles`，并做两次调用：

```cpp
template<typename T, bool Is_causal>
void run_mla_fwd_hdim128(Mla_fwd_params &params, cudaStream_t stream) {
    constexpr static int Headdim = 128;
    auto [cc_major, cc_minor] = get_compute_capability(get_current_device());
    bool is_sm8x = cc_major == 8 && cc_minor > 0;

    // 推理：禁用 dropout（你们已确认）
    // 所以我们只实现 !Is_dropout 分支即可，进一步减少模板编译
    if (is_sm8x) {
        // sm86/sm89 causal: 64x64x4
        if constexpr(Is_causal) {
            using KT = Flash_fwd_kernel_traits<Headdim, 64, 64, 4, false, false, T>;
            params.dv_start = 0; params.dv_len = 512;
            run_mla_fwd_tiles<KT, 4>(params, stream);
            if (params.dc > 512) { params.dv_start = 512; params.dv_len = params.dc - 512; run_mla_fwd_tiles<KT, 3>(params, stream); }
        } else {
            using KT = Flash_fwd_kernel_traits<Headdim, 128, 32, 4, false, false, T>;
            params.dv_start = 0; params.dv_len = 512;
            run_mla_fwd_tiles<KT, 4>(params, stream);
            if (params.dc > 512) { params.dv_start = 512; params.dv_len = params.dc - 512; run_mla_fwd_tiles<KT, 3>(params, stream); }
        }
    } else {
        // H100/H200: 128x64x4
        using KT = Flash_fwd_kernel_traits<Headdim, 128, 64, 4, false, false, T>;
        params.dv_start = 0; params.dv_len = 512;
        run_mla_fwd_tiles<KT, 4>(params, stream);
        if (params.dc > 512) { params.dv_start = 512; params.dv_len = params.dc - 512; run_mla_fwd_tiles<KT, 3>(params, stream); }
    }
}
```

> 说明：你们只关心 H200，所以实际只要 else 分支那一套 KT 就行。把 sm8x 分支保留是为了兼容调试环境。

