# 1) 直接可粘贴：`mla_mask.h`（替换 TODO）
```cpp
#pragma once
#include "namespace_config.h"
#include <cute/tensor.hpp>

namespace FLASH_NAMESPACE {
using namespace cute;

// acc_s tensor layout与 flash-attn 一致：tensor has shape (nrow=(2, MMA_M), ncol=(2, MMA_N))
// 这个实现基于你贴的 apply_mask，使用 lane_id -> col_idx 映射
// 需要额外知道：每个 mi 对应的全局 q 行 index（q_idx_base + mi）
template <typename Engine, typename Layout>
__forceinline__ __device__ void apply_mask_mla(
    Tensor<Engine, Layout> &tensor,
    const int n_offset,      // n_block * kBlockN
    const int q_idx_base,    // 全局 q 行起点（通常 m_block*kBlockM + (tidx/32)*16）
    const int max_q_rows,    // kNWarps*16（或你们传的那个）
    const int kv_len,
    const int past,          // kv_len - seqlen_q
    const bool causal,
    const int col_idx_offset_ = 0
) {
    static_assert(Layout::rank == 2, "Only support 2D Tensor");
    const int lane_id = threadIdx.x % 32;
    const int col_idx_offset = col_idx_offset_ + (lane_id % 4) * 2;

    #pragma unroll
    for (int nj = 0; nj < size<1, 1>(tensor); ++nj) {
        const int col_idx_base = col_idx_offset + nj * 8;

        #pragma unroll
        for (int j = 0; j < size<1, 0>(tensor); ++j) {
            const int col_in_block = col_idx_base + j;         // 0..kBlockN-1 within this fragment mapping
            const int k_idx = n_offset + col_in_block;         // global key index

            // padding mask: k_idx >= kv_len
            const bool invalid_k = (k_idx >= kv_len);

            // causal append mask: k_idx > past + q_idx
            // 我们对每个 mi 单独判断（q_idx 不同）
            if (invalid_k) {
                #pragma unroll
                for (int mi = 0; mi < size<0>(tensor); ++mi) {
                    tensor(mi, make_coord(j, nj)) = -INFINITY;
                }
            } else if (causal) {
                #pragma unroll
                for (int mi = 0; mi < size<0>(tensor); ++mi) {
                    const int q_idx = q_idx_base + mi;  // 这里的 mi 对应该线程负责的行
                    // 超过实际 q 范围的行（最后一个 block）也直接 mask 掉，防止 OOB 参与 softmax
                    const bool invalid_q = (q_idx >= max_q_rows);
                    const bool invalid_causal = (k_idx > past + q_idx);
                    if (invalid_q || invalid_causal) {
                        tensor(mi, make_coord(j, nj)) = -INFINITY;
                    }
                }
            }
        }
    }
}

} // namespace FLASH_NAMESPACE
```

