```cpp
// === Epilogue: store each 128-wide tile using the same path as flash-attn (rO -> sO -> gO) ===

// Reuse sQ's memory as sO staging (same as flash-attn)
Tensor sO = make_tensor(sQ.data(), typename Kernel_traits::SmemLayoutO{});  // (SMEM_M, SMEM_N)

// Smem store for O
auto smem_tiled_copy_O = make_tiled_copy_C(typename Kernel_traits::SmemCopyAtomO{}, tiled_mma);
auto smem_thr_copy_O = smem_tiled_copy_O.get_thread_slice(tidx);
Tensor taccOsO = smem_thr_copy_O.partition_D(sO);  // ((Atom,AtomNum), PIPE_M, PIPE_N)

// Global output tensor (seqlen_q, dc)
Tensor mO = make_tensor(make_gmem_ptr(o_base),
                        make_shape(seqlen_q, params.dc),
                        make_stride(params.o_row_stride, _1{}));

typename Kernel_traits::GmemTiledCopyO gmem_tiled_copy_O;
auto gmem_thr_copy_gO = gmem_tiled_copy_O.get_thread_slice(tidx);
Tensor tOsO = gmem_thr_copy_gO.partition_S(sO);  // ((Atom,AtomNum), ATOM_M, ATOM_N)

#pragma unroll
for (int i = 0; i < NTILES; ++i) {
    const int dv_out = params.dv_start + i * kHeadDim;  // kHeadDim==128

    // gO tile: (kBlockM, 128) at (m_block, dv_out)
    Tensor gO = local_tile(mO, Shape<Int<kBlockM>, Int<kHeadDim>>{}, make_coord(m_block, dv_out));

    Tensor rO = FLASH_NAMESPACE::convert_type<Element>(acc_o[i]);

    // Partition rO and gO according to the gmem copy
    Tensor taccOrO = smem_thr_copy_O.retile_S(rO);         // ((Atom,AtomNum), MMA_M, MMA_N)
    // NOTE: taccOsO already points to sO

    // If Share_Q_K_smem, need to sync before reusing sQ as sO (same as original flash-attn)
    if (Kernel_traits::Share_Q_K_smem) { __syncthreads(); }

    // 1) write rO to shared sO
    cute::copy(smem_tiled_copy_O, taccOrO, taccOsO);

    // 2) write shared sO to global gO
    Tensor tOgO = gmem_thr_copy_gO.partition_D(gO);        // ((Atom,AtomNum), ATOM_M, ATOM_N)

    // We need predicates for M (for last block) and N (should always be valid since kHeadDim=128 fixed)
    // Construct identity layout for gO to compute row index
    Tensor cO = make_identity_tensor(make_shape(size<0>(gO), size<1>(gO)));  // (BLK_M, BLK_N)
    Tensor tOcO = gmem_thr_copy_gO.partition_D(cO);
    Tensor tOpO = make_tensor<bool>(make_shape(size<2>(tOgO)));

    // N pred: always true since tile width is exactly 128 and dv_out+128 <= dc is guaranteed by NTILES and dv_len.
    // M pred: ensure we don't write beyond seqlen_q in last block.
    #pragma unroll
    for (int k = 0; k < size(tOpO); ++k) {
        // row index within this tile
        int row = get<0>(tOcO(0, 0, k));
        tOpO(k) = (row < seqlen_q - m_block * kBlockM);
    }

    // Make sure sO is ready
    __syncthreads();

    // Clear_OOB_K must be false; Clear_OOB_MN true to prevent OOB rows writes
    FLASH_NAMESPACE::copy</*Is_even_MN=*/false, /*Is_even_K=*/true, /*Clear_OOB_MN=*/true, /*Clear_OOB_K=*/false>(
        gmem_tiled_copy_O, tOsO, tOgO, tOcO, tOpO, seqlen_q - m_block * kBlockM
    );

    __syncthreads();
}
```

### 这段 epilogue 做了什么
- 对每个 tile：
  1) `acc_o[i]`（fp32 fragment）转 bf16 `rO`
  2) 按 flash-attn 原来的 `SmemLayoutO` 写到 shared `sO`
  3) 再用 `GmemTiledCopyO` 从 `sO` 写回 global 的 `gO`
- 行越界用 `tOpO` predicate 避免最后一个 m_block 写出界
